'use strict';

// ----------------------------
// Dados (simulação)
// ----------------------------
const produtos = [
  { id: 1, nome: 'Café', preco: 12.5 },
  { id: 2, nome: 'Leite', preco: 6.9 },
  { id: 3, nome: 'Pão', preco: 9.0 },
  { id: 4, nome: 'Bolo de cenoura', preco: 25.0 },
  { id: 5, nome: 'Café com leite', preco: 15.0 },
  { id: 6, nome: 'Chocolate', preco: 14.0 },
  { id: 7, nome: 'Açúcar', preco: 7.5 },
];

// ----------------------------
// Utilitários (strings/nums)
// ----------------------------
function normalizarTexto(x) {
  return String(x ?? '').trim().toLowerCase();
}

function toNumberOrNull(raw) {
  const s = String(raw ?? '').trim().replace(',', '.');
  if (s.length === 0) return null;
  const n = Number(s);
  return Number.isNaN(n) ? null : n;
}

function clampInt(n, min, max) {
  const x = Math.trunc(Number(n));
  if (Number.isNaN(x)) return min;
  return Math.max(min, Math.min(max, x));
}

// ----------------------------
// URL <-> estado
// ----------------------------
function lerEstadoDaUrl() {
  const sp = new URLSearchParams(window.location.search);
  const q = sp.get('q') ?? '';
  const min = toNumberOrNull(sp.get('min'));
  const max = toNumberOrNull(sp.get('max'));
  const page = clampInt(sp.get('page') ?? 1, 1, 999);
  return { q, min, max, page };
}

function escreverEstadoNaUrl(estado) {
  const sp = new URLSearchParams();

  const q = String(estado.q ?? '').trim();
  if (q.length) sp.set('q', q);

  if (estado.min !== null && estado.min !== undefined) sp.set('min', String(estado.min));
  if (estado.max !== null && estado.max !== undefined) sp.set('max', String(estado.max));

  sp.set('page', String(estado.page ?? 1));

  const qs = sp.toString();
  const nova = qs.length ? `?${qs}` : window.location.pathname;
  history.replaceState(null, '', nova);
}

// ----------------------------
// Filtro + paginação (puro)
// ----------------------------
const PAGE_SIZE = 3;

function filtrar(estado) {
  const qn = normalizarTexto(estado.q);

  let lista = produtos;
  if (qn.length) lista = lista.filter((p) => normalizarTexto(p.nome).includes(qn));
  if (typeof estado.min === 'number') lista = lista.filter((p) => p.preco >= estado.min);
  if (typeof estado.max === 'number') lista = lista.filter((p) => p.preco <= estado.max);

  const total = lista.length;
  const totalPages = Math.max(1, Math.ceil(total / PAGE_SIZE));
  const page = clampInt(estado.page, 1, totalPages);

  const start = (page - 1) * PAGE_SIZE;
  const itens = lista.slice(start, start + PAGE_SIZE);

  return { itens, total, page, totalPages };
}

// ----------------------------
// UI
// ----------------------------
function assertEl(sel) {
  const el = document.querySelector(sel);
  if (!el) console.error(`[busca] elemento não encontrado: ${sel}`);
  return el;
}

const form = assertEl('#form');
const elQ = assertEl('#q');
const elMin = assertEl('#min');
const elMax = assertEl('#max');
const elInfo = assertEl('#info');
const elLista = assertEl('#lista');
const btnPrev = assertEl('#prev');
const btnNext = assertEl('#next');

const hasDom = Boolean(form && elQ && elMin && elMax && elInfo && elLista && btnPrev && btnNext);
let estado = { q: '', min: null, max: null, page: 1 };

function render() {
  if (!hasDom) return;

  const res = filtrar(estado);
  elInfo.textContent = `Total: ${res.total} | Página: ${res.page}/${res.totalPages}`;

  elLista.innerHTML = '';
  for (const p of res.itens) {
    const li = document.createElement('li');
    li.textContent = `${p.nome} — R$ ${p.preco.toFixed(2)}`;
    elLista.appendChild(li);
  }

  btnPrev.disabled = res.page <= 1;
  btnNext.disabled = res.page >= res.totalPages;
}

function hidratarCampos() {
  if (!hasDom) return;
  elQ.value = estado.q ?? '';
  elMin.value = estado.min ?? '';
  elMax.value = estado.max ?? '';
}

function aplicarEstado(novo) {
  estado = { ...estado, ...novo };
  escreverEstadoNaUrl(estado);
  hidratarCampos();
  render();
}

function onSubmit(ev) {
  ev.preventDefault();
  if (!hasDom) return;

  const q = String(elQ.value ?? '').trim();
  const min = toNumberOrNull(elMin.value);
  const max = toNumberOrNull(elMax.value);
  aplicarEstado({ q, min, max, page: 1 });
}

function onPrev() { aplicarEstado({ page: estado.page - 1 }); }
function onNext() { aplicarEstado({ page: estado.page + 1 }); }

if (hasDom) {
  estado = lerEstadoDaUrl();
  hidratarCampos();
  render();

  form.addEventListener('submit', onSubmit);
  btnPrev.addEventListener('click', onPrev);
  btnNext.addEventListener('click', onNext);

  console.log('[busca] pronto');
}
